import React, { useState, useEffect } from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css";
import { FaBars, FaTimes } from "react-icons/fa";

const Navbar = () => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 900);
  const [menuOpen, setMenuOpen] = useState(false);

  // Handle window resize
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 900);
    };

    handleResize(); // Ensure it runs on mount
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    document.body.style.overflow = menuOpen ? "hidden" : "auto";
    return () => (document.body.style.overflow = "auto");
  }, [menuOpen]);

  return (
    <div className="container">
      <nav className="navbar">
        <div className="navbar-logo">
          <Link to="HOME" smooth={true} duration={500}>
            <img src="./images/logo.png" alt="Logo" />
          </Link>
        </div>

        {isMobile ? (
          <div className="hamburger" onClick={() => setMenuOpen(!menuOpen)}>
            {menuOpen ? <FaTimes className="icon" /> : <FaBars className="icon" />}
          </div>
        ) : (
          <ul className="navbar-links">
            {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
              <li key={section}>
                <Link to={section} smooth={true} duration={500} activeClass="active" spy={true} offset={-70}>
                  {section.replace(/-/g, " ")}
                </Link>
              </li>
            ))}
          </ul>
        )}

       {menuOpen && isMobile && (
  <div className="mobile-menu">
    {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
      <li key={section}>
        <Link 
          to={section} 
          smooth={true} 
          duration={500} 
          activeClass="active" 
          spy={true} 
          offset={-70} 
          onClick={() => setMenuOpen(false)}
        >
          {section.replace(/-/g, " ")}
        </Link>
      </li>
    ))}
    <li className="close-button" onClick={() => setMenuOpen(false)}>
      <FaTimes className="icon" /> Close
    </li>
  </div>
)}
      </nav>
    </div>
  );
};

export default Navbar;
